module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

parameter IDLE = 3'b000;
parameter LOAD = 3'b001;
parameter CALCULATE = 3'b010;
parameter OUTPUT = 3'b011;

reg [2:0] state, next_state;
reg [3:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] sum[0:3];
reg [15:0] mul_out_reg;
reg [15:0] temp[0:7];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @* begin
    case(state)
        IDLE: begin
            if(mul_en_in) begin
                next_state = LOAD;
            end else begin
                next_state = IDLE;
            end
        end
        LOAD: begin
            if(!mul_en_in) begin
                next_state = CALCULATE;
            end else begin
                next_state = LOAD;
            end
        end
        CALCULATE: begin
            if(mul_en_out_reg[2]) begin
                next_state = OUTPUT;
            end else begin
                next_state = CALCULATE;
            end
        end
        OUTPUT: begin
            if(!mul_en_in) begin
                next_state = IDLE;
            end else begin
                next_state = OUTPUT;
            end
        end
        default: next_state = IDLE;
    endcase
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg <= 4'd0;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[2:0], mul_en_in};
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'd0;
        mul_b_reg <= 8'd0;
    end else if (mul_en_in) begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end else begin
        mul_a_reg <= 8'd0;
        mul_b_reg <= 8'd0;
    end
end

genvar i;
generate
    for(i = 0; i < 8; i=i+1) begin
        assign temp[i] = mul_b_reg[i] ? {8'd0, mul_a_reg} << i : 16'd0;
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        sum[0] <= 16'd0;
        sum[1] <= 16'd0;
        sum[2] <= 16'd0;
        sum[3] <= 16'd0;
    end else begin
        sum[0] <= temp[0] + temp[1];
        sum[1] <= temp[2] + temp[3];
        sum[2] <= temp[4] + temp[5];
        sum[3] <= temp[6] + temp[7];
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out_reg <= 16'd0;
    end else begin
        mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
    end
end

assign mul_out = mul_en_out_reg[3] ? mul_out_reg : 16'd0;
endmodule
